#include <bits/stdc++.h>
#define ull unsigned long long
#define mk(x,y) make_pair(x,y)
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb(x) push_back(x)
#define CI const int
using namespace std;
il ll read()
{
    ll x=0,f=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=getchar();}
    return x*f;
}
void write(ll x)
{
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=2e5+5;
int n, m, root,f[MAXN][2];
bool c[MAXN];
vector<int> t[MAXN];
void dfs(int u, int fa)
{
    if(u <= m) return ; 
    FOI(s, t[u])
    {
        if(s != fa)
        {
            dfs(s, u);
            f[u][0] += min(f[s][0] - 1, f[s][1]);
            f[u][1] += min(f[s][1] - 1, f[s][0]);
        }		
    }
}

int main(void) 
{
    n = read(), m = read();
    FOR(i, 1, m)
    {
        c[i] = read();
    }
    FOR(i, 1, n - 1)
    {
        int u = read(), v = read();
        t[u].pb(v), t[v].pb(u);
    }
    FOR(i, 1, n)
    {
        f[i][0] = f[i][1] = 1, root = i;
        if(i <= m) f[i][! c[i]] = inf;
    }	
    dfs(root, 0);
    writeln(min(f[root][0], f[root][1]));
    return false;
}
